class BirdDeterrentNode(Node):
    def __init__(self):
        super().__init__('bird_deterrent')
        self.sub = self.create_subscription(DetectionArray, '/bird_detections', self.cb, 10)
        self.sound_pub = self.create_publisher(String, '/deterrent/sound', 10)

    def cb(self, msg):
        for det in msg.detections:
            if det.confidence > 0.8 and det.distance < 20:
                self.sound_pub.publish(String(data='predator_call.wav'))

